        uint x,
        uint x2,
        uint x3,
        uint x4,
        uint x5,
        uint x6,
        uint x7,
        uint x8
    ) {
        a = 1;
    }
}
```

doing #152 from a branch instead of a fork to test @mattiaerre codecov theory

Before this PR is merged:
```Solidity
if (thisIsAnExtremelyVeryLongAndComplicatedCondition) {
    doSomething();
}

while (thisIsAnExtremelyVeryLongAndComplicatedCondition) {
    doSomething();
}

for (thisIsAVeryLongVariableInitiation; thisIsAnExtremelyVeryLongAndComplicatedCondition; thisIsAComplicatedLoopRule) {
    doSomething();
}
```

After this PR is merged:
```Solidity
if (
    thisIsAnExtremelyVeryLongAndComplicatedCondition
) {
    doSomething();
}

while (
    thisIsAnExtremelyVeryLongAndComplicatedCondition
) {
    doSomething();
}

for (
    thisIsAVeryLongVariableInitiation;
    thisIsAnExtremelyVeryLongAndComplicatedCondition;
    thisIsAComplicatedLoopRule
) {
    doSomething();
}
```

